    import ast 

    def parse_expression(expr): 
        """Parses a string expression using ast module.""" 
        try: 
            tree = ast.parse(expr) 
            return tree 
        except SyntaxError as e: 
            print("Syntax Error:", str(e)) 

    def evaluate_expression(node): 
        """Evaluates a parsed expression using eval() function.""" 
        try: 
            result = ast.literal_eval(ast.dump(node).replace('\n', '')) 
            return result 
        except SyntaxError as e: 
            print("Syntax Error:", str(e))

